        start, end = 0, len(nums) - 1

        while start < end:

            mid = start + (end - start) // 2

            if nums[mid] > nums[end]:
                start = mid + 1
            else:
                end = mid

        return nums[start]

class Solution:
    def rob(self, nums):
        n = len(nums)

        if n == 1:
            return nums[0]

        dp = [0] * n

        dp[0] = nums[0]
        dp[1] = max(nums[0], nums[1])

        for i in range(2, n):
            dp[i] = max(dp[i-1], nums[i] + dp[i-2])

        return dp[-1]

class Solution(object):
    def numIslands(self, grid):

        if not grid:
            return 0

        rows, cols = len(grid), len(grid[0])
        count = 0
        directions = [(1,0), (-1,0), (0,1), (0,-1)]

        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == "1":
                    count += 1

                    # Flood fill one island and mark it as visited.
                    stack = [(r, c)]
                    grid[r][c] = "0"

                    while stack:
                        x, y = stack.pop()

                        for dx, dy in directions:
                            nx, ny = x + dx, y + dy

                            if 0 <= nx < rows and 0 <= ny < cols and grid[nx][ny] == "1":
                                grid[nx][ny] = "0"
                                stack.append((nx, ny))

        return count

