class Solution:
    def rob(self, nums):

        def get_max(nums):
            prev_rob = max_rob = 0

            for cur_val in nums:
                temp = max(max_rob, prev_rob + cur_val)
                prev_rob = max_rob
                max_rob = temp

            return max_rob

        return max(get_max(nums[:-1]), get_max(nums[1:]), nums[0])

import bisect

class Solution:
    def lengthOfLIS(self, nums):
        tails = []

        for num in nums:
            idx = bisect.bisect_left(tails, num)

            if idx == len(tails):
                tails.append(num)
            else:
                tails[idx] = num

        return len(tails)

class Solution:
    def coinChange(self, coins, amount):
        min_coins = [amount + 1] * (amount + 1)
        min_coins[0] = 0

        for i in range(1, amount + 1):
            for c in coins:
                if i - c >= 0:
                    min_coins[i] = min(min_coins[i], 1 + min_coins[i - c])

        return min_coins[-1] if min_coins[-1] != amount + 1 else -1

class Solution(object):
    def topKFrequent(self, nums, k):
        n = len(nums)
        occur = {}

        for num in nums:
            occur[num] = occur.get(num, 0) + 1

        bucket = [[] for _ in range(n + 1)]
        for key in occur:
            bucket[occur[key]].append(key)

        res = []
        for i in range(n, 0, -1):
            for val in bucket[i]:
                res.append(val)
                if len(res) == k:
                    return res

