class Solution(object):
    def mergeTrees(self, t1, t2):

        if not t1 and not t2:
            return None

        ans = TreeNode((t1.val if t1 else 0) + (t2.val if t2 else 0))
        ans.left = self.mergeTrees(t1 and t1.left, t2 and t2.left)
        ans.right = self.mergeTrees(t1 and t1.right, t2 and t2.right)
        return ans

class Solution(object):
    def maxAreaOfIsland(self, grid):

        if not grid or not grid[0]:
            return 0

        rows, cols = len(grid), len(grid[0])
        visited = set()
        max_island = 0

        def dfs(r, c):
            if r not in range(rows) or c not in range(cols) or (r, c) in visited or grid[r][c] == 0:
                return 0

            visited.add((r, c))

            # Explore 4-directionally and accumulate area.
            return 1 + dfs(r+1, c) + dfs(r-1, c) + dfs(r, c+1) + dfs(r, c-1)

        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 1 and (r, c) not in visited:
                    max_island = max(max_island, dfs(r, c))

        return max_island

import heapq


class KthLargest(object):
    def __init__(self, k, nums):
        self.k = k
        self.nums = nums
        heapq.heapify(self.nums)
        while len(self.nums) > k:
            heapq.heappop(self.nums)

    def add(self, val):
        heapq.heappush(self.nums, val)
        if len(self.nums) > self.k:
            heapq.heappop(self.nums)

        return self.nums[0]

class Solution:
    def kthGrammar(self, n, k):
        are_values_same = True

        n = 2**(n - 1)

        while n != 1:
            n //= 2

            if k > n:
                k -= n
                are_values_same = not are_values_same

        return 0 if are_values_same else 1

class Solution(object):
    def numUniqueEmails(self, emails):
        unique_email = set()

        for email in emails:
            local, domain = email.split("@")
            plus_index = local.find("+")
            if plus_index != -1:
                local = local[:plus_index]
            local = local.replace(".", "")
            unique_email.add(local + "@" + domain)

        return len(unique_email)

class Solution(object):
    def shipWithinDays(self, weights, D):
        left, right = max(weights), sum(weights)
        while left < right:
            mid, need, cur = (left + right) / 2, 1, 0
            for w in weights:
                if cur + w > mid:
                    need += 1
                    cur = 0
                cur += w
            if need > D: left = mid + 1
            else: right = mid
        return left
